function fork(bytes32 ilk, address src, address dst, int dink, int dart) external {
    Urn storage u = urns[ilk][src];
    Urn storage v = urns[ilk][dst];
    Ilk storage i = ilks[ilk];

    u.ink = _sub(u.ink, dink);
    u.art = _sub(u.art, dart);
    v.ink = _add(v.ink, dink);
    v.art = _add(v.art, dart);

    uint utab = _mul(u.art, i.rate);
    uint vtab = _mul(v.art, i.rate);

    // both sides consent
    require(both(wish(src, msg.sender), wish(dst, msg.sender)), "Vat/not-allowed");

    // both sides safe
    require(utab <= _mul(u.ink, i.spot), "Vat/not-safe-src");
    require(vtab <= _mul(v.ink, i.spot), "Vat/not-safe-dst");

    // both sides non-dusty
    require(either(utab >= i.dust, u.art == 0), "Vat/dust-src");
    require(either(vtab >= i.dust, v.art == 0), "Vat/dust-dst");
}

// Kick off a new auction
    function kick(uint lot, uint bid) external auth returns (uint id) {
        require(live == 1, "Flapper/not-live");
        require(kicks < uint(-1), "Flapper/overflow");
        fill = add256(fill, lot);
        require(fill <= lid, "Flapper/over-lid");
        id = ++kicks;

        bids[id].bid = bid;
        bids[id].lot = lot;
        bids[id].guy = msg.sender;  // configurable??
        bids[id].end = add(uint48(now), tau);

        vat.move(msg.sender, address(this), lot);

        emit Kick(id, lot, bid);
    }

function tend(uint id, uint lot, uint bid) external {
    require(live == 1, "Flapper/not-live");
    require(bids[id].guy != address(0), "Flapper/guy-not-set");
    require(bids[id].tic > now || bids[id].tic == 0, "Flapper/already-finished-tic");
    require(bids[id].end > now, "Flapper/already-finished-end");

    require(lot == bids[id].lot, "Flapper/lot-not-matching");
    require(bid >  bids[id].bid, "Flapper/bid-not-higher");
    require(mul(bid, ONE) >= mul(beg, bids[id].bid), "Flapper/insufficient-increase");

    if (msg.sender != bids[id].guy) {
        gem.move(msg.sender, bids[id].guy, bids[id].bid);
        bids[id].guy = msg.sender;
    }
    gem.move(msg.sender, address(this), bid - bids[id].bid);

    bids[id].bid = bid;
    bids[id].tic = add(uint48(now), ttl);
}

function avg(SD59x18 x, SD59x18 y) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    int256 yInt = y.unwrap();

    unchecked {
        // This operation is equivalent to `x / 2 +  y / 2`, and it can never overflow.
        int256 sum = (xInt >> 1) + (yInt >> 1);

        if (sum < 0) {
            // If at least one of x and y is odd, add 1 to the result, because shifting negative numbers to the right
            // rounds toward negative infinity. The right part is equivalent to `sum + (x % 2 == 1 || y % 2 == 1)`.
            assembly ("memory-safe") {
                result := add(sum, and(or(xInt, yInt), 1))
            }
        } else {
            // Add 1 if both x and y are odd to account for the double 0.5 remainder truncated after shifting.
            result = wrap(sum + (xInt & yInt & 1));
        }
    }
}

function exp(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();

    // Any input less than the threshold returns zero.
    // This check also prevents an overflow for very small numbers.
    if (xInt < uEXP_MIN_THRESHOLD) {
        return ZERO;
    }

    // This check prevents values greater than 192e18 from being passed to {exp2}.
    if (xInt > uEXP_MAX_INPUT) {
        revert Errors.PRBMath_SD59x18_Exp_InputTooBig(x);
    }

    unchecked {
        // Inline the fixed-point multiplication to save gas.
        int256 doubleUnitProduct = xInt * uLOG2_E;
        result = exp2(wrap(doubleUnitProduct / uUNIT));
    }
}

function floor(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    if (xInt < uMIN_WHOLE_SD59x18) {
        revert Errors.PRBMath_SD59x18_Floor_Underflow(x);
    }

    int256 remainder = xInt % uUNIT;
    if (remainder == 0) {
        result = x;
    } else {
        unchecked {
            // Solidity uses C fmod style, which returns a modulus with the same sign as x.
            int256 resultInt = xInt - remainder;
            if (xInt < 0) {
                resultInt -= uUNIT;
            }
            result = wrap(resultInt);
        }
    }
}

function pow(SD59x18 x, SD59x18 y) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    int256 yInt = y.unwrap();

    // If both x and y are zero, the result is `UNIT`. If just x is zero, the result is always zero.
    if (xInt == 0) {
        return yInt == 0 ? UNIT : ZERO;
    }
    // If x is `UNIT`, the result is always `UNIT`.
    else if (xInt == uUNIT) {
        return UNIT;
    }

    // If y is zero, the result is always `UNIT`.
    if (yInt == 0) {
        return UNIT;
    }
    // If y is `UNIT`, the result is always x.
    else if (yInt == uUNIT) {
        return x;
    }

    // Calculate the result using the formula.
    result = exp2(mul(log2(x), y));
}

function sqrt(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    if (xInt < 0) {
        revert Errors.PRBMath_SD59x18_Sqrt_NegativeInput(x);
    }
    if (xInt > uMAX_SD59x18 / uUNIT) {
        revert Errors.PRBMath_SD59x18_Sqrt_Overflow(x);
    }

    unchecked {
        // Multiply x by `UNIT` to account for the factor of `UNIT` picked up when multiplying two SD59x18 numbers.
        // In this case, the two numbers are both the square root.
        uint256 resultUint = Common.sqrt(uint256(xInt * uUNIT));
        result = wrap(int256(resultUint));
    }
}

function flatten(
    MemoryPointer array1,
    MemoryPointer array2
) internal view returns (MemoryPointer newArray) {
    unchecked {
        uint256 arrayLength1 = array1.readUint256();
        uint256 arrayLength2 = array2.readUint256();
        uint256 array1HeadSize = arrayLength1 * 32;
        uint256 array2HeadSize = arrayLength2 * 32;

        newArray = malloc(array1HeadSize + array2HeadSize + 32);
        newArray.write(arrayLength1 + arrayLength2);

        MemoryPointer dst = newArray.next();
        if (arrayLength1 > 0) {
            array1.next().copy(dst, array1HeadSize);
        }
        if (arrayLength2 > 0) {
            array2.next().copy(dst.offset(array1HeadSize), array2HeadSize);
        }
    }
}

function validateContractOfferer(
    address contractOfferer
) public view returns (ErrorsAndWarnings memory errorsAndWarnings) {
    errorsAndWarnings = ErrorsAndWarnings(new uint16[](0), new uint16[](0));

    // Check the EIP165 contract offerer interface
    if (!checkInterface(contractOfferer, CONTRACT_OFFERER_INTERFACE_ID)) {
        errorsAndWarnings.addWarning(
            ContractOffererIssue.InvalidContractOfferer.parseInt()
        );
    }

    // Check if the contract offerer implements SIP-5
    try
        ContractOffererInterface(contractOfferer).getSeaportMetadata()
    {} catch {
        errorsAndWarnings.addWarning(
            ContractOffererIssue.InvalidContractOfferer.parseInt()
        );
    }

    return errorsAndWarnings;
}

function execute(uint256 proposalId, ProposedAction[] memory actions) public payable override {
    if (proposalId >= proposalCount()) {
        revert("execute/INVALID_PROPOSAL_ID");
    }
    Proposal memory proposal = proposals[proposalId];
    _assertProposalExecutable(proposal, actions);

    proposals[proposalId].executed = true;

    for (uint256 i = 0; i != actions.length; i++) {
        ProposedAction memory action = actions[i];
        (bool didSucceed, ) = action.target.call{value: action.value}(action.data);
        require(didSucceed, "execute/ACTION_EXECUTION_FAILED");
    }

    emit ProposalExecuted(proposalId);
}

function getReturns(
    IBalancerPool pool,
    IERC20 fromToken,
    IERC20 destToken,
    uint256[] calldata amounts
)
    external
    view
    returns(uint256[] memory rets)
{
    uint256 swapFee = pool.getSwapFee();
    uint256 fromBalance = pool.getBalance(fromToken);
    uint256 destBalance = pool.getBalance(destToken);
    uint256 fromWeight = pool.getDenormalizedWeight(fromToken);
    uint256 destWeight = pool.getDenormalizedWeight(destToken);

    rets = new uint256[](amounts.length);
    for (uint i = 0; i < amounts.length && amounts[i].mul(2) <= fromBalance; i++) {
        rets[i] = BalancerLib.calcOutGivenIn(
            fromBalance,
            fromWeight,
            destBalance,
            destWeight,
            amounts[i],
            swapFee
        );
    }
}

function _calculateBalancer(
    IERC20 fromToken,
    IERC20 destToken,
    uint256 amount,
    uint256 parts,
    uint256 poolIndex
) internal view returns(uint256[] memory rets, uint256 gas) {
    address[] memory pools = balancerRegistry.getBestPoolsWithLimit(
        address(fromToken.isETH() ? weth : fromToken),
        address(destToken.isETH() ? weth : destToken),
        poolIndex + 1
    );
    if (poolIndex >= pools.length) {
        return (new uint256[](parts), 0);
    }

    rets = balancerHelper.getReturns(
        IBalancerPool(pools[poolIndex]),
        fromToken.isETH() ? weth : fromToken,
        destToken.isETH() ? weth : destToken,
        _linearInterpolation(amount, parts)
    );
    gas = 75_000 + (fromToken.isETH() || destToken.isETH() ? 0 : 65_000);
}

function insert(
  List storage list,
  bytes32 key,
  uint256 value,
  bytes32 lesserKey,
  bytes32 greaterKey
) internal {
  require(
    key != bytes32(0) && key != lesserKey && key != greaterKey && !contains(list, key),
    "invalid key"
  );
  require(
    (lesserKey != bytes32(0) || greaterKey != bytes32(0)) || list.list.numElements == 0,
    "greater and lesser key zero"
  );
  require(contains(list, lesserKey) || lesserKey == bytes32(0), "invalid lesser key");
  require(contains(list, greaterKey) || greaterKey == bytes32(0), "invalid greater key");
  (lesserKey, greaterKey) = getLesserAndGreater(list, value, lesserKey, greaterKey);
  list.list.insert(key, lesserKey, greaterKey);
  list.values[key] = value;
}

function update(
  List storage list,
  bytes32 key,
  uint256 value,
  bytes32 lesserKey,
  bytes32 greaterKey
) internal {
  require(contains(list, key), "key not in list");
  require(key != bytes32(0) && key != lesserKey && key != greaterKey, "invalid key");
  require(
    (lesserKey != bytes32(0) || greaterKey != bytes32(0)) || list.list.numElements == 1,
    "greater and lesser key zero"
  );

  bytes32 oldLesserKey = list.list.elements[key].previousKey;
  bytes32 oldGreaterKey = list.list.elements[key].nextKey;

  if (isValueBetween(list, value, oldLesserKey, oldGreaterKey)) {
    list.values[key] = value;
  } else {
    remove(list, key);
    insert(list, key, value, lesserKey, greaterKey);
  }
}

function _seedChipToTokenMapping(
    address[] memory chipAddresses,
    uint256[] memory tokenIds,
    bool throwIfTokenAlreadyMinted
) internal {
    uint256 tokenIdsLength = tokenIds.length;
    if (tokenIdsLength != chipAddresses.length) {
        revert ArrayLengthMismatch();
    }
    for (uint256 i = 0; i < tokenIdsLength; ++i) {
        address chipAddress = chipAddresses[i];
        uint256 tokenId = tokenIds[i];
        if (throwIfTokenAlreadyMinted && _exists(tokenId)) {
            revert SeedingChipDataForExistingToken();
        }
        _tokenDatas[chipAddress] = TokenData(tokenId, chipAddress, true);
    }
}

function buyTicket() payable external {
    uint256 buyAmount = msg.value;
    require(buyAmount >= _CUR_PRCIE_, "BNB_NOT_ENOUGH");
    uint256 tickets = buyAmount.div(_CUR_PRCIE_);
    require(tickets <= _CUR_SELLING_TICKETS_, "TICKETS_NOT_ENOUGH");
    _USER_TICKETS_[msg.sender] = _USER_TICKETS_[msg.sender].add(tickets);
    _TOTAL_TICKETS_ = _TOTAL_TICKETS_.add(tickets);
    _CUR_SELLING_TICKETS_ = _CUR_SELLING_TICKETS_.sub(tickets);

    uint256 leftOver = msg.value - tickets.mul(_CUR_PRCIE_);
    if(leftOver > 0)
        msg.sender.transfer(leftOver);
    emit BuyTicket(msg.sender, buyAmount - leftOver, tickets);
}

constructor(
    IDelegationManager _delegationManager,
    IEntryPoint _entryPoint,
    string memory _name,
    string memory _domainVersion
)
    EIP712(_name, _domainVersion)
{
    // Short name and version do not use storage in EIP712
    if (bytes(_name).length > 31) revert InvalidEIP712NameLength();
    if (bytes(_domainVersion).length > 31) revert InvalidEIP712VersionLength();

    delegationManager = _delegationManager;
    entryPoint = _entryPoint;
    emit SetDelegationManager(_delegationManager);
    emit SetEntryPoint(_entryPoint);
}

function updateAllowedAggregatorIds(string[] calldata _aggregatorIds, bool[] calldata _statuses) external onlyOwner {
    uint256 aggregatorsLength_ = _aggregatorIds.length;
    if (aggregatorsLength_ != _statuses.length) revert InputLengthsMismatch();

    for (uint256 i = 0; i < aggregatorsLength_; ++i) {
        bytes32 aggregatorIdHash_ = keccak256(abi.encode(_aggregatorIds[i]));
        bool status_ = _statuses[i];
        if (isAggregatorAllowed[aggregatorIdHash_] != status_) {
            isAggregatorAllowed[aggregatorIdHash_] = status_;

            emit ChangedAggregatorIdStatus(aggregatorIdHash_, _aggregatorIds[i], status_);
        }
    }
}

function _setMarketSupplyCaps(
    MToken[] calldata mTokens,
    uint[] calldata newSupplyCaps
) external {
    require(
        msg.sender == admin || msg.sender == supplyCapGuardian,
        "only admin or supply cap guardian can set supply caps"
    );

    uint numMarkets = mTokens.length;
    uint numSupplyCaps = newSupplyCaps.length;

    require(
        numMarkets != 0 && numMarkets == numSupplyCaps,
        "invalid input"
    );

    for (uint i = 0; i < numMarkets; i++) {
        supplyCaps[address(mTokens[i])] = newSupplyCaps[i];
        emit NewSupplyCap(mTokens[i], newSupplyCaps[i]);
    }
}

function cancelAsk(address _tokenContract, uint256 _tokenId) external nonReentrant {
    // Get the ask for the specified token
    StoredAsk storage ask = askForNFT[_tokenContract][_tokenId];

    // If token is still owned by seller, only seller or operator can cancel (otherwise public)
    if (
        IERC721(_tokenContract).ownerOf(_tokenId) == ask.seller &&
        msg.sender != ask.seller &&
        !IERC721(_tokenContract).isApprovedForAll(ask.seller, msg.sender)
    ) {
        revert NOT_TOKEN_OWNER_OR_OPERATOR();
    }

    emit AskCanceled(_tokenContract, _tokenId, _getFullAsk(ask));

    // Remove the ask from storage
    delete askForNFT[_tokenContract][_tokenId];
}

function executeOperation(
    address[] calldata assets,
    uint256[] calldata amounts,
    uint256[] calldata premiums,
    address initiator,
    bytes calldata params
) external returns (bool) {
    if (initiator != address(this)) revert Cellar__ExternalInitiator();
    if (msg.sender != aavePool) revert Cellar__CallerNotAavePool();

    AdaptorCall[] memory data = abi.decode(params, (AdaptorCall[]));

    // Run all adaptor calls.
    _makeAdaptorCalls(data);

    // Approve pool to repay all debt.
    for (uint256 i = 0; i < amounts.length; ++i) {
        ERC20(assets[i]).safeApprove(aavePool, (amounts[i] + premiums[i]));
    }

    return true;
}

function _addPart(IntakeStruct memory partIntake) internal {
    uint64 partId = partIntake.partId;
    Part memory part = partIntake.part;

    if (partId == uint64(0)) revert RMRKIdZeroForbidden();
    if (_parts[partId].itemType != ItemType.None)
        revert RMRKPartAlreadyExists();
    if (part.itemType == ItemType.None) revert RMRKBadConfig();
    if (part.itemType == ItemType.Fixed && part.equippable.length != 0)
        revert RMRKBadConfig();

    _parts[partId] = part;
    _partIds.push(partId);

    emit AddedPart(
        partId,
        part.itemType,
        part.z,
        part.equippable,
        part.metadataURI
    );
}

function addFeeds(
  string[] memory feedIds,
  string[] memory feedNames,
  int192[] memory deviationPercentagePPMs,
  uint32[] memory stalenessSeconds
) external onlyOwner feedsAreValid(feedIds, feedNames, deviationPercentagePPMs, stalenessSeconds) {
  for (uint256 i = 0; i < feedIds.length; i++) {
    string memory feedId = feedIds[i];
    if (s_feedMapping[feedId].active) {
      revert DuplicateFeed(feedId);
    }
    _updateFeed(feedId, feedNames[i], deviationPercentagePPMs[i], stalenessSeconds[i]);
    s_feedMapping[feedId].active = true;

    s_feeds.push(feedId);
  }
}

function _swapOnCurveY(
    IERC20 fromToken,
    IERC20 destToken,
    uint256 amount,
    uint256 /*flags*/
) internal {
    int128 i = (fromToken == dai ? 1 : 0) +
        (fromToken == usdc ? 2 : 0) +
        (fromToken == usdt ? 3 : 0) +
        (fromToken == tusd ? 4 : 0);
    int128 j = (destToken == dai ? 1 : 0) +
        (destToken == usdc ? 2 : 0) +
        (destToken == usdt ? 3 : 0) +
        (destToken == tusd ? 4 : 0);
    if (i == 0 || j == 0) {
        return;
    }

    fromToken.universalApprove(address(curveY), amount);
    curveY.exchange_underlying(i - 1, j - 1, amount, 0);
}

function getLevelMatrixParent(uint256 nftId, uint256 nextLevel) public view override returns (uint256, uint256[] memory) {

    uint256 currentParent = directUplinks[nftId];
    uint256 checkNum = 0;
    uint256[] memory overtakenTmp = new uint256[](5);
    while (accountLevels[currentParent] < nextLevel) {

        overtakenTmp[checkNum] = currentParent;
        currentParent = directUplinks[currentParent];

        checkNum++;

        if (checkNum == 5) {
            currentParent = 1;
            break;
        }
    }

    uint256[] memory overtakenUsers = new uint256[](checkNum);
    for (uint256 x = 0; x < checkNum; x++) {
        overtakenUsers[x] = overtakenTmp[x];
    }

    return (currentParent, overtakenUsers);
}

function _rpow(uint x, uint n, uint b) internal pure returns (uint z) {
  assembly {
    switch x case 0 {switch n case 0 {z := b} default {z := 0}}
    default {
      switch mod(n, 2) case 0 { z := b } default { z := x }
      let half := div(b, 2)  // for rounding.
      for { n := div(n, 2) } n { n := div(n,2) } {
        let xx := mul(x, x)
        if iszero(eq(div(xx, x), x)) { revert(0,0) }
        let xxRound := add(xx, half)
        if lt(xxRound, xx) { revert(0,0) }
        x := div(xxRound, b)
        if mod(n,2) {
          let zx := mul(z, x)
          if and(iszero(iszero(x)), iszero(eq(div(zx, x), z))) { revert(0,0) }
          let zxRound := add(zx, half)
          if lt(zxRound, zx) { revert(0,0) }
          z := div(zxRound, b)
        }
      }
    }
  }
}

function mulDiv18(uint256 x, uint256 y) pure returns (uint256 result) {
    uint256 prod0;
    uint256 prod1;
    assembly ("memory-safe") {
        let mm := mulmod(x, y, not(0))
        prod0 := mul(x, y)
        prod1 := sub(sub(mm, prod0), lt(mm, prod0))
    }

    if (prod1 == 0) {
        unchecked {
            return prod0 / UNIT;
        }
    }

    if (prod1 >= UNIT) {
        revert PRBMath_MulDiv18_Overflow(x, y);
    }

    uint256 remainder;
    assembly ("memory-safe") {
        remainder := mulmod(x, y, UNIT)
        result := mul(
            or(
                div(sub(prod0, remainder), UNIT_LPOTD),
                mul(sub(prod1, gt(remainder, prod0)), add(div(sub(0, UNIT_LPOTD), UNIT_LPOTD), 1))
            ),
            UNIT_INVERSE
        )
    }
}

