function getDeployed(bytes32 salt, address creator) internal pure returns (address) {
    address proxy = keccak256(
        abi.encodePacked(
            // Prefix:
            bytes1(0xFF),
            // Creator:
            creator,
            // Salt:
            salt,
            // Bytecode hash:
            PROXY_BYTECODE_HASH
        )
    ).fromLast20Bytes();

    return
        keccak256(
            abi.encodePacked(
                // 0xd6 = 0xc0 (short RLP prefix) + 0x16 (length of: 0x94 ++ proxy ++ 0x01)
                // 0x94 = 0x80 + 0x14 (0x14 = the length of an address, 20 bytes, in hex)
                hex"d6_94",
                proxy,
                hex"01" // Nonce of the proxy contract (1)
            )
        ).fromLast20Bytes();
}

function highestByteSet(uint self) internal pure returns (uint8 highest) {
    require(self != 0);
    uint ret;
    if (self & 0xffffffffffffffffffffffffffffffff00000000000000000000000000000000 != 0) {
        ret += 16;
        self >>= 128;
    }
    if (self & 0xffffffffffffffff0000000000000000 != 0) {
        ret += 8;
        self >>= 64;
    }
    if (self & 0xffffffff00000000 != 0) {
        ret += 4;
        self >>= 32;
    }
    if (self & 0xffff0000 != 0) {
        ret += 2;
        self >>= 16;
    }
    if (self & 0xff00 != 0) {
        ret += 1;
    }
    highest = uint8(ret);
}

